// src/middleware/database-instrumentation.js
//
// Database query instrumentation for PostgreSQL
// Adds trace context to query comments for correlation in slow query logs
//
// Generated by: Phase 3 observability spine - TASK 6 (Backend Instrumentation)

const { trace } = require('@opentelemetry/api');

/**
 * Wrap a database query function to inject trace context
 * Adds trace_id/span_id to query comments for PostgreSQL slow query logging
 */
function instrumentDatabaseQuery(queryFn, dbName = 'postgres') {
  return async function(...args) {
    const span = trace.getActiveSpan();
    const traceId = span ? span.spanContext().traceId : null;
    const spanId = span ? span.spanContext().spanId : null;
    
    // If this is a string query (first arg), inject trace context as comment
    if (args.length > 0 && typeof args[0] === 'string') {
      const query = args[0];
      
      // Add trace context comment to the beginning of query
      // PostgreSQL and many other databases support /* comment */ syntax
      const enhancedQuery = `
        /*+ trace_id='${traceId}' span_id='${spanId}' service='code-server-backend' */
        ${query}
      `.trim();
      
      args[0] = enhancedQuery;
      
      // Start timing span
      const startTime = Date.now();
      
      try {
        // Execute query
        const result = await queryFn.apply(this, args);
        
        // Record success
        const duration = Date.now() - startTime;
        if (span) {
          span.setAttributes({
            'db.system': dbName,
            'db.operation': extractOperation(query),
            'db.duration_ms': duration,
            'db.query_size': query.length,
            'db.success': true,
          });
          
          if (result && result.rows) {
            span.setAttributes({
              'db.rows_affected': result.rows.length,
            });
          }
        }
        
        return result;
      } catch (error) {
        // Record error
        const duration = Date.now() - startTime;
        if (span) {
          span.recordException(error);
          span.setAttributes({
            'db.system': dbName,
            'db.operation': extractOperation(query),
            'db.duration_ms': duration,
            'db.error': error.message || 'Unknown database error',
            'db.success': false,
          });
        }
        
        throw error;
      }
    } else {
      // For non-string queries, just call the function
      return queryFn.apply(this, args);
    }
  };
}

/**
 * Create a database connection pool wrapper that instruments all queries
 */
function instrumentDatabasePool(pool, dbName = 'postgres') {
  const originalQuery = pool.query.bind(pool);
  
  pool.query = function(...args) {
    const span = trace.getActiveSpan();
    const traceId = span ? span.spanContext().traceId : null;
    const spanId = span ? span.spanContext().spanId : null;
    
    // Add trace context to query
    if (args.length > 0 && typeof args[0] === 'string') {
      const query = args[0];
      const enhancedQuery = `
        /*+ trace_id='${traceId}' span_id='${spanId}' service='code-server-backend' */
        ${query}
      `.trim();
      
      args[0] = enhancedQuery;
    }
    
    // Wrap callback if present
    if (args.length > 1 && typeof args[args.length - 1] === 'function') {
      const originalCallback = args[args.length - 1];
      const startTime = Date.now();
      
      args[args.length - 1] = function(err, result) {
        const duration = Date.now() - startTime;
        
        if (err) {
          if (span) {
            span.recordException(err);
            span.setAttributes({
              'db.system': dbName,
              'db.error': err.message || 'Unknown database error',
              'db.duration_ms': duration,
              'db.success': false,
            });
          }
        } else {
          if (span) {
            span.setAttributes({
              'db.system': dbName,
              'db.success': true,
              'db.duration_ms': duration,
            });
            
            if (result && result.rows) {
              span.setAttributes({
                'db.rows_affected': result.rows.length,
              });
            }
          }
        }
        
        return originalCallback(err, result);
      };
    }
    
    return originalQuery.apply(this, args);
  };
  
  return pool;
}

/**
 * Extract operation type from SQL query
 */
function extractOperation(query) {
  if (!query || typeof query !== 'string') {
    return 'unknown';
  }
  
  const upperQuery = query.toUpperCase().trim();
  
  if (upperQuery.startsWith('SELECT')) return 'select';
  if (upperQuery.startsWith('INSERT')) return 'insert';
  if (upperQuery.startsWith('UPDATE')) return 'update';
  if (upperQuery.startsWith('DELETE')) return 'delete';
  if (upperQuery.startsWith('CREATE')) return 'create';
  if (upperQuery.startsWith('DROP')) return 'drop';
  if (upperQuery.startsWith('ALTER')) return 'alter';
  if (upperQuery.startsWith('TRUNCATE')) return 'truncate';
  if (upperQuery.startsWith('BEGIN')) return 'begin_transaction';
  if (upperQuery.startsWith('COMMIT')) return 'commit';
  if (upperQuery.startsWith('ROLLBACK')) return 'rollback';
  
  return 'unknown';
}

/**
 * Create a wrapper for prepared statements
 */
function instrumentPreparedStatement(client, stmt, dbName = 'postgres') {
  const originalExecute = stmt.execute.bind(stmt);
  
  stmt.execute = function(...args) {
    const span = trace.getActiveSpan();
    const traceId = span ? span.spanContext().traceId : null;
    const spanId = span ? span.spanContext().spanId : null;
    
    const startTime = Date.now();
    const name = stmt.name || 'unknown_statement';
    
    // Add trace context as prepared statement parameters
    // (Most databases don't support comments in parameter bindings)
    
    const result = originalExecute.apply(this, args);
    const duration = Date.now() - startTime;
    
    if (span) {
      span.setAttributes({
        'db.system': dbName,
        'db.operation': 'prepared_statement',
        'db.statement_name': name,
        'db.duration_ms': duration,
        'trace_id': traceId,
        'span_id': spanId,
      });
    }
    
    return result;
  };
  
  return stmt;
}

/**
 * Utility to add trace context to raw SQL strings
 */
function addTraceContextToSQL(sql, traceId = null, spanId = null) {
  if (!traceId) {
    const span = trace.getActiveSpan();
    if (span) {
      traceId = span.spanContext().traceId;
      spanId = span.spanContext().spanId;
    }
  }
  
  if (!traceId) {
    return sql;  // No trace context available
  }
  
  return `
    /*+ trace_id='${traceId}' span_id='${spanId}' service='code-server-backend' */
    ${sql}
  `.trim();
}

module.exports = {
  instrumentDatabaseQuery,
  instrumentDatabasePool,
  instrumentPreparedStatement,
  addTraceContextToSQL,
  extractOperation,
};
